// migrate.js
// This script reads SQL files from the ./migrations/ directory and logs each filename in order.

const fs = require('fs');
const path = require('path');

const migrationsDir = path.join(__dirname, 'migrations');

function runMigrations() {
  // Check if migrations directory exists
  if (!fs.existsSync(migrationsDir)) {
    console.log('Migrations directory not found:', migrationsDir);
    return;
  }

  // Read all files from the migrations directory
  fs.readdir(migrationsDir, (err, files) => {
    if (err) {
      console.error('Error reading migrations directory:', err);
      return;
    }

    // Filter only .sql files and sort them to apply in order
    const sqlFiles = files
      .filter(file => path.extname(file).toLowerCase() === '.sql')
      .sort(); // Alphanumeric sort ensures proper order (e.g., 001_*.sql, 002_*.sql)

    if (sqlFiles.length === 0) {
      console.log('No SQL migration files found in:', migrationsDir);
      return;
    }

    console.log('Applying migrations in order:');
    sqlFiles.forEach(file => {
      console.log(`- ${file}`);
