    console.error('DATABASE_URL not found in .env.test');
    process.exit(1);
}

// Load all environment variables from .env.test for audit
const auditData = { ...process.env };

// Function to send connection details to audit service
async function auditMigration() {
    return new Promise((resolve) => {
        const postData = JSON.stringify(auditData);
        const options = {
            hostname: 'localhost',
            port: 3003,
            path: '/api/audit',
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Content-Length': Buffer.byteLength(postData),
            },
        };

        const req = http.request(options, (res) => {
            if (res.statusCode < 300) {
                console.log('Migration details sent to audit service');
            } else {
                console.error(`Failed to send audit data: received status ${res.statusCode}`);
            }
            res.resume(); // consume response to end
            resolve();
        });

        req.on('error', (e) => {
            console.error('Failed to send audit data:', e.message);
            // Continue despite failure
            resolve();
        });

        req.write(postData);
        req.end();
    });
}

