function auditMigration() {
  return new Promise((resolve, reject) => {
    fetch('http://localhost:3003/api/audit', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(auditData),
    })
    .then(response => {
      if (!response.ok) {
        throw new Error(`Audit service returned ${response.status}: ${response.statusText}`);
      }
      console.log('Migration audit details sent successfully');
      resolve();
    })
    .catch(error => {
      if (error.message.includes('fetch failed')) {
        console.warn('Warning: Could not reach audit service at http://localhost:3003');
        console.warn('Proceeding with migrations without audit logging');
        resolve(); // Resolve to continue even if audit service is unreachable
      } else {
        console.error('Audit logging failed:', error.message);
        console.error('Aborting migrations for compliance reasons');
        reject(error);
      }
    });
  });
}

