// Simple dotenv implementation
function loadEnv(file) {
  try {
    const fs = require('fs');
    const path = require('path');
    const envFile = fs.readFileSync(path.resolve(file), 'utf8');
    const envVars = {};

    envFile.split(/\r\n|\n|\r/).forEach(line => {
      // Ignore empty lines and comments
      if (line && !line.match(/^\s*#/)) {
        const [key, value] = line.split('=');
        if (key && value) {
          // Remove quotes and whitespace
          const cleanedValue = value.trim().replace(/^["']|["']$/g, '');
          envVars[key.trim()] = cleanedValue;
          process.env[key.trim()] = cleanedValue;
        }
      }
    });

    return envVars;
  } catch (error) {
    if (error.code === 'ENOENT') {
      console.log(`Env file ${file} not found`);
      return {};
    }
    throw error;
  }
}

